def find_lowest_interest_rate_hedges():
    years = [2014, 2013, 2012]
    lowest_hedges = float('inf')

    for year in years:
        hedges = cell(year, 'Interest Rate Hedges')
        if hedges < lowest_hedges:
            lowest_hedges = hedges

    result = lowest_hedges
    return result

